/**
 * @fileoverview Custom Element factory for RazyUI components.
 *
 * Creates a CustomElement class that wraps an existing RazyUI component,
 * bridging declarative HTML usage to the imperative constructor pattern.
 *
 * Design decisions:
 * - NO Shadow DOM — JIT utility classes and component CSS must remain in the global scope
 * - Config via `config` attribute (JSON) + individual observed attributes
 * - Children with `slot="..."` attributes mapped to component template slots
 * - `.control` property exposes the component's `getControl()` API
 * - Deferred initialization via `queueMicrotask` so child elements are parsed
 *
 * Usage:
 *   import { defineElement } from './shared/custom-element.js';
 *   import Accordion from './Accordion.js';
 *
 *   defineElement('rui-accordion', Accordion, {
 *       observedAttrs: ['active', 'variant', 'multiple'],
 *       attrMap: { active: 'activeIndex' },
 *   });
 *
 * HTML:
 *   <rui-accordion active="0" variant="boxed">...</rui-accordion>
 *
 * @module shared/custom-element
 */

/**
 * Parse an attribute string value to the appropriate JavaScript type.
 *
 * @param {string} val — raw attribute string
 * @returns {*} parsed value
 */
function parseAttrValue(val) {
    // Boolean-like values
    if (val === '' || val === 'true') return true;
    if (val === 'false') return false;
    if (val === 'null') return null;
    if (val === 'undefined') return undefined;

    // Numeric values
    const num = Number(val);
    if (!isNaN(num) && val.trim() !== '') return num;

    // JSON values (arrays, objects)
    if (val.length > 1) {
        const first = val[0], last = val[val.length - 1];
        if ((first === '[' && last === ']') || (first === '{' && last === '}')) {
            try { return JSON.parse(val); }
            catch { /* fall through to string */ }
        }
    }

    return val;
}

// Tracks tags we've registered via defineElement, keyed to the source
// Component class. Lets repeated calls with the same Component (idempotent
// re-loads via razyui.load) return silently, while a *different* class
// trying to claim the same tag still emits a warning.
const _ruiRegistry = new Map();

/**
 * Create and register a Custom Element class from a RazyUI component class.
 *
 * @param {string} tag — custom element tag name (must contain a hyphen, e.g. 'rui-accordion')
 * @param {Function} Component — the RazyUI component constructor class
 * @param {object} [options]
 * @param {string[]} [options.observedAttrs=[]] — attribute names to observe for changes
 * @param {Object<string, string>} [options.attrMap={}] — attribute name → config property name map
 * @param {string} [options.configAttr='config'] — attribute name for JSON config object
 * @param {Function} [options.onConnect] — hook called after component initialization
 * @param {Function} [options.onDisconnect] — hook called before component destruction
 * @returns {Function} the registered Custom Element class
 */
function defineElement(tag, Component, options = {}) {
    const {
        observedAttrs = [],
        attrMap = {},
        configAttr = 'config',
        componentName = Component.name,
        onConnect = null,
        onDisconnect = null,
        reinitAttrs = [],
    } = options;

    // Skip if already defined
    if (customElements.get(tag)) {
        // Idempotent re-registration of the same Component (e.g. razyui.load
        // called again after HMR / async race) — silent return.
        if (_ruiRegistry.get(tag) === Component) {
            return customElements.get(tag);
        }
        console.warn(`[rui] Custom element <${tag}> already defined`);
        return customElements.get(tag);
    }

    class RuiElement extends HTMLElement {
        /** @type {object|null} — component instance */
        #instance = null;

        /** @type {object|null} — control API from getControl() */
        #control = null;

        /** @type {boolean} — prevents re-entry during init */
        #initializing = false;

        static get observedAttributes() {
            return [configAttr, ...observedAttrs];
        }

        connectedCallback() {
            // Defer to next microtask so children / light DOM are fully parsed.
            // This is important for elements with slotted children.
            queueMicrotask(() => {
                if (this.isConnected && !this.#instance) {
                    this.#init();
                }
            });
        }

        disconnectedCallback() {
            onDisconnect?.(this, this.#control);
            this.#control?.destroy?.();
            this.#instance = null;
            this.#control = null;
        }

        attributeChangedCallback(name, oldVal, newVal) {
            if (oldVal === newVal) return;
            if (!this.#control) return; // not yet initialized

            if (name === configAttr) {
                // Full re-init on config change
                this.#control?.destroy?.();
                this.#instance = null;
                this.#control = null;
                this.#init();
                return;
            }

            if (reinitAttrs.includes(name)) {
                this.#control?.destroy?.();
                this.#instance = null;
                this.#control = null;
                this.#init();
                return;
            }

            // Map attribute to control property and update
            const prop = attrMap[name] || camelCase(name);
            if (this.#control && prop in this.#control) {
                this.#control[prop] = parseAttrValue(newVal);
            }
        }

        /**
         * Access the underlying component control API.
         * @returns {object|null}
         */
        get control() {
            return this.#control;
        }

        /**
         * Initialize the component.
         * @private
         */
        #init() {
            if (this.#initializing) return;
            this.#initializing = true;

            try {
                // Build config from attributes
                const config = {};

                // 1. Parse JSON config attribute
                const jsonStr = this.getAttribute(configAttr);
                if (jsonStr) {
                    try {
                        Object.assign(config, JSON.parse(jsonStr));
                    } catch (e) {
                        console.warn(`[rui] Invalid config JSON on <${tag}>:`, e);
                    }
                }

                // 2. Override with individual observed attributes
                for (const attr of observedAttrs) {
                    const val = this.getAttribute(attr);
                    if (val !== null) {
                        const key = attrMap[attr] || camelCase(attr);
                        config[key] = parseAttrValue(val);
                    }
                }

                // 3. Collect slotted children
                config._slots = this.#collectSlots();

                // 4. Instantiate component (element = this, config)
                this.#instance = new Component(this, config);
                this.#control = this.#instance.getControl?.() ?? null;
                if (this.#control && typeof globalThis.razyui?.attachComponentControl === 'function') {
                    this.#control = globalThis.razyui.attachComponentControl(this.#control, {
                        host: this,
                        componentName,
                    });
                }

                // 5. Hook
                onConnect?.(this, this.#control, config);

            } catch (e) {
                console.error(`[rui] Error initializing <${tag}>:`, e);
            } finally {
                this.#initializing = false;
            }
        }

        /**
         * Collect children with `data-slot` or `slot` attributes, grouped by slot name.
         * Children without either attribute go into the 'default' slot.
         *
         * @private
         * @returns {Object<string, HTMLElement[]>}
         */
        #collectSlots() {
            const slots = {};
            for (const child of this.children) {
                const name = child.getAttribute('data-slot')
                    || child.getAttribute('slot')
                    || 'default';
                (slots[name] ??= []).push(child);
            }
            return slots;
        }
    }

    // Register the element
    customElements.define(tag, RuiElement);
    _ruiRegistry.set(tag, Component);
    return RuiElement;
}

/**
 * Convert kebab-case attribute name to camelCase property name.
 *
 * @param {string} str — e.g. 'row-height', 'show-filter'
 * @returns {string} — e.g. 'rowHeight', 'showFilter'
 */
function camelCase(str) {
    return str.replace(/-([a-z])/g, (_, c) => c.toUpperCase());
}

/**
 * Batch-register multiple components as Custom Elements.
 *
 * @param {Array<{tag: string, component: Function, options?: object}>} defs
 */
function defineElements(defs) {
    for (const { tag, component, options } of defs) {
        defineElement(tag, component, options);
    }
}

/**
 * Register a custom element from a RazyUI component definition object.
 *
 * Reads `tag`, `name`, `observedAttrs`, and `attrMap` directly from the
 * def.js export, eliminating boilerplate in each component's barrel file.
 *
 * @param {object} def — component definition (e.g. AccordionDef)
 * @param {Function} Component — the RazyUI component constructor class
 * @param {object} [extraOptions] — additional options forwarded to defineElement()
 * @returns {Function} the registered Custom Element class
 */
function registerFromDef(def, Component, extraOptions = {}) {
    return defineElement(def.tag, Component, {
        observedAttrs: def.observedAttrs || [],
        attrMap: def.attrMap || {},
        componentName: def.name,
        reinitAttrs: def.reinitAttrs || [],
        ...extraOptions,
    });
}

export { defineElement, defineElements, registerFromDef, parseAttrValue, camelCase };
